SELECT
  CONVERSATION_ID,
  CUSTOMER_ID,
  ACCOUNT_ID,
  CARD_ID,
  APPLICATION_NAME,
  DNIS,
  ANI,
  CALL_START_TIMESTAMP,
  CALL_END_TIMESTAMP,
  SELECTED_LANGUAGE,
  VERSION,
  INGESTION_TIMESTAMP,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'language_step'), NULL) AS LANGUAGE_STEP,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'welcome_step'), NULL) AS WELCOME_STEP,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'broadcast_step'), NULL) AS BROADCAST_STEP,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'authenticated'), NULL) AS AUTHENTICATED,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'card_validated'), NULL) AS CARD_VALIDATED,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'dob_validated'), NULL) AS DOB_VALIDATED,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'phone_validated'), NULL) AS PHONE_VALIDATED,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'otp_validated'), NULL) AS OTP_VALIDATED,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'balance_playback_step'), NULL) AS BALANCE_PLAYBACK_STEP,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'card_replacement_step'), NULL) AS CARD_REPLACEMENT_STEP,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'address_update_step'), NULL) AS ADDRESS_UPDATE_STEP,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'ivr_transfer'), NULL) AS IVR_TRANSFER,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'transfer_requested_by_user'), NULL) AS TRANSFER_REQUESTED_BY_USER,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'intent_step'), NULL) AS INTENT_STEP,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'requested_intents'), NULL) AS REQUESTED_INTENTS,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'birth_year'), NULL) AS BIRTH_YEAR,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'phone_number'), NULL) AS PHONE_NUMBER,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'route_point'), NULL) AS ROUTE_POINT,
  COALESCE((SELECT JSON_EXTRACT_SCALAR(item, '$.value') FROM UNNEST(JSON_EXTRACT_ARRAY(t.PAYLOAD, '$')) AS item WHERE JSON_EXTRACT_SCALAR(item, '$.key') = 'exit_skill_sets'), NULL) AS EXIT_SKILL_SETS,
  PAYLOAD
FROM `pcb-{env}-landing.domain_customer_contact_centre.CALL_CONVERSATION_STATE` t
where t.PAYLOAD is not null;